import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { registerUser } from "../../api/authApi";

function Register() {

  const navigate = useNavigate();

  const [formData, setFormData] =
    useState({
      name: "",
      email: "",
      password: "",
      role: "faculty",
      school: "",
      department: ""
    });

  const handleChange = (e) => {

    setFormData({
      ...formData,
      [e.target.name]:
        e.target.value
    });
  };

  const handleSubmit =
    async (e) => {

      e.preventDefault();

      try {

        await registerUser(
          formData
        );

        alert(
          "Registration Successful"
        );

        navigate("/login");

      } catch (error) {

        alert(
          error.response?.data?.message ||
          "Registration Failed"
        );

      }
    };

  return (

    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        background:
          "linear-gradient(135deg,#2563eb,#1e3a8a)"
      }}
    >

      <div
        style={{
          width: "500px",
          background: "#fff",
          padding: "40px",
          borderRadius: "15px",
          boxShadow:
            "0 10px 25px rgba(0,0,0,0.2)"
        }}
      >

        <h1
          style={{
            textAlign: "center",
            marginBottom: "10px"
          }}
        >
          SRIHER IQAC
        </h1>

        <p
          style={{
            textAlign: "center",
            color: "#666",
            marginBottom: "25px"
          }}
        >
          Create New Account
        </p>

        <form
          onSubmit={
            handleSubmit
          }
        >

          <input
            name="name"
            placeholder="Full Name"
            onChange={
              handleChange
            }
            style={inputStyle}
          />

          <input
            name="email"
            type="email"
            placeholder="Email"
            onChange={
              handleChange
            }
            style={inputStyle}
          />

          <input
            name="password"
            type="password"
            placeholder="Password"
            onChange={
              handleChange
            }
            style={inputStyle}
          />

          <select
            name="role"
            onChange={
              handleChange
            }
            style={inputStyle}
          >
            <option value="faculty">
              Faculty
            </option>

            <option value="hod">
              HOD
            </option>

            <option value="dean">
              Dean
            </option>
          </select>

          <input
            name="school"
            placeholder="School"
            onChange={
              handleChange
            }
            style={inputStyle}
          />

          <input
            name="department"
            placeholder="Department"
            onChange={
              handleChange
            }
            style={inputStyle}
          />

          <button
            type="submit"
            style={{
              width: "100%",
              padding: "12px",
              background:
                "#2563eb",
              color: "#fff",
              border: "none",
              borderRadius: "8px",
              cursor: "pointer",
              fontSize: "16px"
            }}
          >
            Register
          </button>

        </form>

        <p
          style={{
            textAlign: "center",
            marginTop: "20px"
          }}
        >
          Already have an account?{" "}
          <Link to="/login">
            Login
          </Link>
        </p>

      </div>

    </div>
  );
}

const inputStyle = {
  width: "100%",
  padding: "12px",
  marginBottom: "15px",
  borderRadius: "8px",
  border: "1px solid #ccc",
  boxSizing: "border-box"
};

export default Register;
